import React from "react";
import { PRIORITY_META, STATUS_META, formatDate } from "../utils/costants";

export default function FeatureCard({ feature, onEdit, onDelete, onStatusChange }) {
  const pm = PRIORITY_META[feature.priority];
  const sm = STATUS_META[feature.status];
  const isAdminMode = Boolean(onEdit); // If onEdit is provided, we're in admin mode

  return (
    <article className={`card status-${feature.status.replace(" ", "-").toLowerCase()}`}>
      <div className="card-top">
        <span className="priority-badge" style={{ "--badge-color": pm.color }}>
          {feature.priority}
        </span>
        <span className="card-date">{formatDate(feature.createdAt)}</span>
      </div>

      {/* Show image if present */}
      {feature.image && (
        <div style={{ margin: '8px 0', textAlign: 'center' }}>
          <img
            src={`http://localhost:5000/api/features/images/${feature.image}`}
            alt={feature.title}
            style={{ maxWidth: '100%', maxHeight: 180, borderRadius: 8, boxShadow: '0 1px 8px #0001' }}
          />
        </div>
      )}

      <h3 className="card-title">{feature.title}</h3>
      <p className="card-desc">{feature.description}</p>

      <div className="card-footer">
        {isAdminMode ? (
          <>
            <button
              className={`status-btn status-${feature.status.replace(" ", "-").toLowerCase()}`}
              onClick={() => onStatusChange && onStatusChange(feature.status === "Open" ? "In Progress" : feature.status === "In Progress" ? "Completed" : "Open")}
              title={sm.label}
            >
              <span className="status-icon">{sm.icon}</span>
              {sm.label}
            </button>
            <div style={{ display: "flex", gap: "8px" }}>
              <button
                className="btn btn-sm btn-secondary"
                onClick={() => onEdit && onEdit()}
                title="Edit feature"
              >
                ✎ Edit
              </button>
              <button
                className="btn btn-sm btn-danger"
                onClick={() => onDelete && onDelete()}
                title="Delete feature"
              >
                🗑 Delete
              </button>
            </div>
          </>
        ) : (
          <span
            className={`status-btn status-${feature.status.replace(" ", "-").toLowerCase()}`}
            title={sm.label}
          >
            <span className="status-icon">{sm.icon}</span>
            {sm.label}
          </span>
        )}
      </div>
    </article>
  );
}
